// Example: drop messages where temperature is out-of-range, rename keys
const raw = msg.payload;
let data = typeof raw === 'string' ? JSON.parse(raw) : raw;

// Drop messages with null/undefined temperature
if (data.temperature === undefined || data.temperature === null) {
  node.warn('Dropping message: missing temperature');
  msg.drop = true;
  return msg;
}

// Clamp unreasonable readings
if (data.temperature > 200 || data.temperature < -100) {
  msg.drop = true;
  return msg;
}

// Rename 'temperature' -> 'temp_c', add unit
msg.payload = {
  temp_c: data.temperature,
  humidity: data.humidity ?? null,
  unit: 'Celsius',
  ts: Date.now()
};

return msg;
